const rows = $input.all().map(i => i.json);
const totalFact = rows.reduce((s, r) => s + Number(r.total_facturado || 0), 0);
const totalCobr = rows.reduce((s, r) => s + Number(r.total_cobrado || 0), 0);
const ticket = rows.length ? rows.reduce((s,r) => s + Number(r.ticket_promedio || 0), 0) / rows.length : 0;
return [{ json: {
  summary: { total_facturado: totalFact, total_cobrado: totalCobr, num_doctores: rows.length, ticket_promedio: ticket },
  rows
} }];

const rows = $input.all().map(i => i.json);
const totalTrat = rows.reduce((s, r) => s + Number(r.cantidad || 0), 0);
const totalFact = rows.reduce((s, r) => s + Number(r.total_facturado || 0), 0);
const cats = new Set(rows.map(r => r.category)).size;
const avg = totalTrat ? totalFact / totalTrat : 0;
// Add pct
const withPct = rows.map(r => ({ ...r, pct_total: totalFact ? Number(r.total_facturado) / totalFact * 100 : 0 }));
return [{ json: {
  summary: { total_tratamientos: totalTrat, total_facturado: totalFact, precio_promedio: avg, num_categorias: cats },
  rows: withPct
} }];

const basis = $('GET /reports/honorarios').first().json.query?.basis || 'cobrado';
const rows = $input.all().map(i => ({
  ...i.json,
  base_calculo: basis === 'facturado' ? Number(i.json.total_facturado) : Number(i.json.total_cobrado),
  honorario_calculado: (basis === 'facturado' ? Number(i.json.total_facturado) : Number(i.json.total_cobrado)) * Number(i.json.porcentaje) / 100
}));
const totalBase = rows.reduce((s, r) => s + r.base_calculo, 0);
const totalHon = rows.reduce((s, r) => s + r.honorario_calculado, 0);
const avgPct = rows.length ? rows.reduce((s, r) => s + Number(r.porcentaje), 0) / rows.length : 0;
return [{ json: {
  summary: { total_base: totalBase, total_honorarios: totalHon, num_doctores: rows.length, porcentaje_promedio: avgPct },
  rows
} }];
